// src/components/layout/Header.jsx (modificado)
import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { colors, spacing, typography, shadows, borderRadius, transitions } from '../../styles/theme';

const Header = () => {
  // Estado para detectar si la página ha sido scrolleada
  const [isScrolled, setIsScrolled] = useState(false);
  // Estado para el hover
  const [hoveredItem, setHoveredItem] = useState(null);
  // Estado para controlar la visibilidad del header
  const [isVisible, setIsVisible] = useState(true);
  // Estado para almacenar la posición de scroll anterior
  const [lastScrollY, setLastScrollY] = useState(0);
  // Estado para controlar el login del usuario
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  // Estado para el nombre del usuario
  const [userName, setUserName] = useState('');

  // Usar useLocation en lugar de withRouter
  const location = useLocation();

  // Comprobar si el usuario está logueado al cargar el componente
  useEffect(() => {
    const userToken = localStorage.getItem('userToken');
    const name = localStorage.getItem('userName');

    if (userToken) {
      setIsLoggedIn(true);
      setUserName(name || 'Usuario');
    }
  }, []);

  // Detectar scroll para efectos de navegación
  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;

      if (currentScrollY > lastScrollY) {
        setIsVisible(false);
      } else {
        setIsVisible(true);
      }

      setLastScrollY(currentScrollY);
      setIsScrolled(currentScrollY > 50);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [lastScrollY]);

  // Cerrar sesión
  const handleLogout = () => {
    // Eliminar datos del localStorage
    localStorage.removeItem('userToken');
    localStorage.removeItem('userName');

    // Actualizar estado
    setIsLoggedIn(false);
    setUserName('');

    // Redireccionar a inicio (opcional)
    window.location.href = '/';
  };

  // Verificar si la ruta está activa
  const isActive = (path) => {
    if (path === '/') {
      return location.pathname === '/';
    }
    if (path === '/blog') {
      return location.pathname.startsWith('/blog') ||
        location.pathname.includes('/post/') ||
        location.pathname.includes('/category/');
    }
    return location.pathname.startsWith(path);
  };

  // Estilos del header
  const styles = {
    header: {
      backgroundColor: isScrolled ? "rgba(240, 248, 247, 0.95)" : colors.white,
      padding: `${spacing.md} 0`,
      boxShadow: isScrolled ? shadows.md : shadows.sm,
      position: "fixed",
      top: isVisible ? 0 : '-100px',
      width: "100%",
      zIndex: 100,
      transition: transitions.default
    },
    headerSpacer: {
      height: "80px",
      width: "100%"
    },
    container: {
      maxWidth: "1200px",
      margin: "0 auto",
      padding: `0 ${spacing.md}`,
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center"
    },
    logo: {
      display: "flex",
      alignItems: "center",
      color: colors.primary,
      textDecoration: "none",
      fontSize: typography.fontSize.xl,
      fontWeight: typography.fontWeight.bold,
      transition: transitions.default
    },
    logoIcon: {
      backgroundColor: colors.background,
      borderRadius: borderRadius.md,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      marginRight: spacing.sm,
      transition: transitions.default,
      width: "42px",
      height: "42px",
      overflow: "hidden"
    },
    navLinks: {
      display: "flex",
      gap: spacing.xl,
      alignItems: "center" // Alinear elementos verticalmente
    },
    navLink: (isActivePath) => ({
      color: isActivePath ? colors.primary : colors.textSecondary,
      textDecoration: "none",
      fontWeight: typography.fontWeight.medium,
      position: "relative",
      padding: `${spacing.xs} 0`,
      transition: transitions.default
    }),
    profileIcon: {
      width: "40px",
      height: "40px",
      borderRadius: borderRadius.circle,
      backgroundColor: colors.primaryLight,
      overflow: "hidden",
      boxShadow: shadows.sm,
      border: `2px solid ${colors.white}`,
      transition: transitions.default,
      cursor: "pointer"
    },
    profileImg: {
      width: "100%",
      height: "100%",
      objectFit: "cover"
    },
    // Nuevo estilo para el botón de login
    loginButton: {
      padding: `${spacing.xs} ${spacing.lg}`,
      backgroundColor: colors.secondary,
      color: colors.primary,
      borderRadius: borderRadius.round,
      fontWeight: typography.fontWeight.medium,
      textDecoration: "none",
      transition: transitions.default,
      display: "flex",
      alignItems: "center",
      gap: spacing.xs,
      marginLeft: spacing.md,
      border: "none",
      cursor: "pointer",
      fontSize: typography.fontSize.sm,
      '&:hover': {
        backgroundColor: colors.primary,
        color: colors.white,
        transform: "translateY(-2px)",
        boxShadow: shadows.sm
      }
    },
    // Nuevo estilo para el contenedor de usuario logueado
    userContainer: {
      display: "flex",
      alignItems: "center",
      gap: spacing.sm
    },
    // Estilo para el nombre de usuario
    userName: {
      color: colors.primary,
      fontWeight: typography.fontWeight.medium,
      fontSize: typography.fontSize.sm
    },
    // Estilo para botón de logout
    logoutButton: {
      background: "none",
      border: "none",
      color: colors.primaryLight,
      cursor: "pointer",
      fontSize: typography.fontSize.sm,
      padding: `${spacing.xs} ${spacing.sm}`,
      borderRadius: borderRadius.sm,
      transition: transitions.default,
      '&:hover': {
        color: colors.primary,
        backgroundColor: `${colors.gray100}`
      }
    }
  };

  const navItems = [
    { path: '/', label: 'Inicio' },
    { path: '/category/tecnicas-de-estudio', label: 'Blog' },
    { path: '/about', label: 'Acerca de' },
    { path: '/contact', label: 'Contacto' },
    { path: '/admin/post', label: 'Crear Post', admin: true }
  ];

  return (
    <>
      <header style={styles.header}>
        <div style={styles.container}>
          <Link
            to="/"
            style={styles.logo}
            onMouseEnter={() => setHoveredItem('logo')}
            onMouseLeave={() => setHoveredItem(null)}
          >
            <div style={{
              ...styles.logoIcon,
              transform: hoveredItem === 'logo' ? 'scale(1.1) rotate(5deg)' : 'scale(1)'
            }}>
              <img
                src="/assets/images/educstation-logo.png"
                alt="EducStation Logo"
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "contain"
                }}
              />
            </div>
            <span style={{
              color: colors.primary,
              fontWeight: typography.fontWeight.bold
            }}>
              EducStation
            </span>
          </Link>

          <nav style={styles.navLinks}>
            {navItems.map((item, index) => (
              // Solo mostrar enlaces de admin a usuarios con rol admin o enlaces normales a todos
              (!item.admin || (item.admin && isLoggedIn)) && (
                <a
                  key={index}
                  href={item.path}
                  style={styles.navLink(isActive(item.path))}
                  onClick={(e) => {
                    e.preventDefault();
                    window.location.href = item.path;
                  }}
                  onMouseEnter={() => setHoveredItem(`nav-${index}`)}
                  onMouseLeave={() => setHoveredItem(null)}
                >
                  {item.label}
                  <span
                    style={{
                      position: 'absolute',
                      width: isActive(item.path) || hoveredItem === `nav-${index}` ? '100%' : '0%',
                      height: '2px',
                      bottom: 0,
                      left: 0,
                      backgroundColor: colors.primary,
                      transition: transitions.default
                    }}
                  ></span>
                </a>
              )
            ))}

            {/* Mostrar un botón de login o el perfil del usuario */}
            {isLoggedIn ? (
              <div style={styles.userContainer}>
                <span style={styles.userName}>{userName}</span>
                <button
                  style={{
                    ...styles.logoutButton,
                    ...(hoveredItem === 'logout' ? {
                      color: colors.primary,
                      backgroundColor: colors.gray100
                    } : {})
                  }}
                  onClick={handleLogout}
                  onMouseEnter={() => setHoveredItem('logout')}
                  onMouseLeave={() => setHoveredItem(null)}
                >
                  Cerrar sesión
                </button>
              </div>
            ) : (
              <Link
                to="/login"
                style={{
                  ...styles.loginButton,
                  ...(hoveredItem === 'login' ? {
                    backgroundColor: colors.primary,
                    color: colors.white,
                    transform: "translateY(-2px)",
                    boxShadow: shadows.sm
                  } : {})
                }}
                onMouseEnter={() => setHoveredItem('login')}
                onMouseLeave={() => setHoveredItem(null)}
              >
                Iniciar sesión
              </Link>
            )}
          </nav>

          <div
            style={{
              ...styles.profileIcon,
              transform: hoveredItem === 'profile' ? 'translateY(-2px)' : 'translateY(0)',
              boxShadow: hoveredItem === 'profile' ? shadows.md : shadows.sm
            }}
            onMouseEnter={() => setHoveredItem('profile')}
            onMouseLeave={() => setHoveredItem(null)}
          >
            <img src="/assets/images/logoBN.png" alt="Profile" style={styles.profileImg} />
          </div>
        </div>
      </header>
      {/* Añadimos un div espaciador para compensar la altura del header fijo */}
      <div style={styles.headerSpacer}></div>
    </>
  );
}
export default Header;
